tasks.solution:
#include <iostream>

int main() {
    int n;
    if (!(std::cin >> n)) {
        return 0;
    }

    long long result = 1;
    int i = n; // Start from the input number

    while (i > 0) { // Loop until the counter reaches the end
        result = result * i; 
        i--; // Update the counter
    }

    std::cout << result << std::endl;

    return 0;
}
